struct PUVADictConstants {
	constexpr static uint32_t PLANET_BITS =  13;
	constexpr static uint32_t FACE_BITS   =  3;
	constexpr static uint32_t FLAGS_BITS  =  2;
	constexpr static uint32_t LOCAL_U_BITS = 7;
	constexpr static uint32_t LOCAL_V_BITS = 7;

	constexpr static uint32_t PLANET_SHIFT = 0;
	constexpr static uint32_t FACE_SHIFT  = PLANET_SHIFT + PLANET_BITS;
	constexpr static uint32_t FLAGS_SHIFT = FACE_SHIFT + FACE_BITS;
	constexpr static uint32_t LOCAL_U_SHIFT = FLAGS_SHIFT + FLAGS_BITS;
	constexpr static uint32_t LOCAL_V_SHIFT = LOCAL_U_SHIFT + LOCAL_U_BITS;

	constexpr static uint32_t PLANET_MASK = (1u << PLANET_BITS) - 1;
	constexpr static uint32_t FACE_MASK =   (1u << FACE_BITS) - 1;
	constexpr static uint32_t FLAGS_MASK =  (1u << FLAGS_BITS) - 1;
	constexpr static uint32_t LOCAL_U_MASK = (1u << LOCAL_U_BITS) - 1;
	constexpr static uint32_t LOCAL_V_MASK = (1u << LOCAL_V_BITS) - 1;

	constexpr static uint32_t NUM_FACES = 8;
	constexpr static uint32_t ROOT_UV_SIZE = 128;
	
	constexpr static uint32_t GLOBAL_FACE = 6; // not attached to cube, instead attached freely to planet
	
	constexpr static uint8_t NODE_TYPE_UNKNOWN = 0;
	constexpr static uint8_t NODE_TYPE_ROOT = 1;
	constexpr static uint8_t NODE_TYPE_PLANET = 2;
	constexpr static uint8_t NODE_TYPE_FACE = 3;
	constexpr static uint8_t NODE_TYPE_LEAF = 4;
	//constexpr static uint8_t NODE_TYPE_ROOT_ALL // not applicable
	constexpr static uint8_t NODE_TYPE_REMAINDER_FLAG = 1 << 7;
	constexpr static uint8_t NODE_TYPE_PLANET_REMAINDER = NODE_TYPE_PLANET | NODE_TYPE_REMAINDER_FLAG;
	constexpr static uint8_t NODE_TYPE_FACE_REMAINDER = NODE_TYPE_FACE | NODE_TYPE_REMAINDER_FLAG;
	constexpr static uint8_t NODE_TYPE_LEAF_REMAINDER = NODE_TYPE_LEAF | NODE_TYPE_REMAINDER_FLAG;
	
	static const char* nodeTypeToString(const uint8_t nt) {
		switch (nt) {
			case NODE_TYPE_ROOT: return "ROOT";
			case NODE_TYPE_PLANET: return "PLANET";
			case NODE_TYPE_FACE: return "FACE";
			case NODE_TYPE_LEAF: return "LEAF";
			case NODE_TYPE_PLANET_REMAINDER: return "PLANET-R";
			case NODE_TYPE_FACE_REMAINDER: return "FACE-R";
			case NODE_TYPE_LEAF_REMAINDER: return "LEAF-R";
			default: return "(unknown)";
			}
		}
	};
	
