{
  bool PlanetaryFaceUVArchiveDictionary::node::canSplit () const
                                      {
			// is this permitted to split under any circumstances?
			if (type == PUVADictConstants::NODE_TYPE_FACE && face == PUVADictConstants::GLOBAL_FACE)
				return false;
			return true;
			}
}
namespace sttSav
{
  bool PlanetaryFaceUVArchiveDictionary::node::containsExact (unpackedKey const & k) const
                                                               {
			// Returns true if this node contains this key exactly
			if (isRemainder())
				return false;
			
			switch (type) {
				case PUVADictConstants::NODE_TYPE_ROOT:
					return true;
				case PUVADictConstants::NODE_TYPE_PLANET:
					if (planet != k.planet)
						return false;
					return flags == k.flags;
				case PUVADictConstants::NODE_TYPE_FACE:
					if (planet != k.planet || face != k.face)
						return false;
					return flags == k.flags;
				case PUVADictConstants::NODE_TYPE_LEAF:
					if (planet != k.planet || face != k.face || flags != k.flags)
						return false;
					return k.localU >= u && k.localU < u + uvSize &&
						   k.localV >= v && k.localV < v + uvSize;
				default:
					STTSAV_ASSERT(false);
					return false;
				}
			}
}
