namespace sttSav
{
  PlanetaryFaceUVArchiveDictionary::node * PlanetaryFaceUVArchiveDictionary::lookup (node * start, unpackedKey const & key)
                                                                 {
		node* current = start;
		while (current) {
			node* exact = NULL;
			node* remainder = NULL;
			
			if (!current->children.size())
				return current;
			for (node* child : current->children) {
				if (child->containsExact(key)) {
					exact = child;
					break;
					}
				else if (child->isRemainder())
					remainder = child;
				}
			if (exact)
				current = exact;
			else if (remainder)
				current = remainder;
			else
				return current;
			}
		return NULL;
		}
}
namespace sttSav
{
  void PlanetaryFaceUVArchiveDictionary::getArchiveFilename (archiveId const id, char * nameOut, uint32_t & lenOut, uint32_t const maxLen) const
                                                                                                                  {
		node* n = getNodeByArchiveId(id);
		switch (n->type) {
			case PUVADictConstants::NODE_TYPE_PLANET_REMAINDER: 
				lenOut = snprintf(nameOut, maxLen, "planet-r.sav");
				return;
			case PUVADictConstants::NODE_TYPE_PLANET: 
				lenOut = snprintf(nameOut, maxLen, "planet-%i.sav", (int)n->planet);
				return;
			case PUVADictConstants::NODE_TYPE_FACE: 
				{
				if (n->face == PUVADictConstants::GLOBAL_FACE)
					lenOut = snprintf(nameOut, maxLen, "planet-%i-face-g.sav", (int)n->planet);
				else
					lenOut = snprintf(nameOut, maxLen, "planet-%i-face-%i.sav", (int)n->planet, (int)n->face);
				}
				return;
			case PUVADictConstants::NODE_TYPE_LEAF: 
				{
				lenOut = snprintf(nameOut, maxLen, "planet-%i-face-%i-sz%i-u%i-v%i.sav", (int)n->planet, (int)n->face, n->uvSize, n->u, n->v);
				}
				return;
			default:
				STTSAV_ASSERT(false);
			}
		}
}
namespace sttSav
{
  bool PlanetaryFaceUVArchiveDictionary::splitArchive (archiveId const id, STTSAV_VECTOR <recordInfo> const & records, uint32_t const maxArchiveSize, splitResult * resultsOut, uint32_t & numResultsOut, uint32_t const maxResultsOut)
                                                                                                                                                                                                       {
		numResultsOut = 0;

		node* n = getNodeByArchiveId(id);
		if (!n)
			return false;

		if (!n->canSplit())
			return false;

		//////////////////////////////////////////////////////////////////////////
		// Build buckets
		//////////////////////////////////////////////////////////////////////////

		STTSAV_VECTOR<splitBucket> buckets;

		for (const recordInfo& r : records) {
			unpackedKey k(r.key);
			uint32_t bucket = 0;

			switch (n->type) {
				case PUVADictConstants::NODE_TYPE_PLANET_REMAINDER:
					bucket = k.planet;
					break;
				case PUVADictConstants::NODE_TYPE_PLANET:
					bucket = k.face;
					break;
				case PUVADictConstants::NODE_TYPE_FACE:
				case PUVADictConstants::NODE_TYPE_LEAF: {
					const uint32_t parentSize = (n->uvSize == 0) ? PUVADictConstants::ROOT_UV_SIZE : n->uvSize;
					const uint32_t half = parentSize >> 1;
					if (k.localU >= n->u + half)
						bucket |= 1;
					if (k.localV >= n->v + half)
						bucket |= 2;
					break;
					}
				default:
					STTSAV_ASSERT(false);
					return false;
				}

			splitBucket::appendOrInsert(buckets, bucket, r.length);
			}

		//////////////////////////////////////////////////////////////////////////
		// PLANET-R : peel planets.
		//////////////////////////////////////////////////////////////////////////

		if (n->type == PUVADictConstants::NODE_TYPE_PLANET_REMAINDER) {
			std::sort(buckets.rbegin(), buckets.rend());

			uint32_t remaining = 0;
			for (const splitBucket& b : buckets)
				remaining += b.bytes;

			for (const splitBucket& b : buckets) {
				if (remaining <= maxArchiveSize)
					break;

				remaining -= b.bytes;

				node* child = STTSAV_NEW(node);
				child->parent = n->parent;
				child->type = PUVADictConstants::NODE_TYPE_PLANET;
				child->planet = (uint16_t)b.value;
				child->aid = getNextId();

				insertLookup(child);

				n->parent->children.push_back(child);

				STTSAV_ASSERT(numResultsOut < maxResultsOut);

				resultsOut[numResultsOut].aid = child->aid;
				resultsOut[numResultsOut].size = b.bytes;
				++numResultsOut;
				}

			resultsOut[numResultsOut].aid = n->aid;
			resultsOut[numResultsOut].size = remaining;
			++numResultsOut;

			return true;
			}

		//////////////////////////////////////////////////////////////////////////
		// Split this archive into deterministic children.
		//////////////////////////////////////////////////////////////////////////

		clearLookup(n->aid);
		n->aid.value = 0;

		switch (n->type) {
			case PUVADictConstants::NODE_TYPE_PLANET:
				for (uint32_t face = 0;  face <= PUVADictConstants::GLOBAL_FACE;  ++face) {
					node* child = STTSAV_NEW(node);
					child->parent = n;
					child->type = PUVADictConstants::NODE_TYPE_FACE;
					child->planet = n->planet;
					child->face = (uint8_t)face;
					child->flags = n->flags;
					child->aid = getNextId();
					insertLookup(child);
					n->children.push_back(child);
					resultsOut[numResultsOut].aid = child->aid;
					resultsOut[numResultsOut].size = 0;
					++numResultsOut;
					}
				break;

			case PUVADictConstants::NODE_TYPE_FACE:
			case PUVADictConstants::NODE_TYPE_LEAF: {
				const uint8_t parentSize = (n->uvSize == 0) ? PUVADictConstants::ROOT_UV_SIZE : n->uvSize;
				const uint8_t half = parentSize >> 1;

				for (uint32_t q = 0; q < 4; ++q) {
					node* child = STTSAV_NEW(node);
					child->parent = n;
					child->type = PUVADictConstants::NODE_TYPE_LEAF;
					child->planet = n->planet;
					child->face = n->face;
					child->flags = n->flags;
					child->u = n->u;
					child->v = n->v;
					child->uvSize = half;

					if (q & 1)
						child->u += half;
					if (q & 2)
						child->v += half;

					child->aid = getNextId();
					insertLookup(child);
					n->children.push_back(child);
					resultsOut[numResultsOut].aid = child->aid;
					resultsOut[numResultsOut].size = 0;
					++numResultsOut;
					}

				break;
				}

			default:
				STTSAV_ASSERT(false);
				return false;
			}

		//////////////////////////////////////////////////////////////////////////
		// Populate child sizes.
		for (const splitBucket& b : buckets) {
			switch (n->type) {
			case PUVADictConstants::NODE_TYPE_PLANET:
				resultsOut[b.value].size = b.bytes;
				break;
			case PUVADictConstants::NODE_TYPE_FACE:
			case PUVADictConstants::NODE_TYPE_LEAF:
				resultsOut[b.value].size = b.bytes;
				break;
			default:
				break;
				}
			}

		return true;
		}
}
namespace sttSav
{
  bool PlanetaryFaceUVArchiveDictionary::getMergeCandidates (archiveId const id, archiveId * archivesOut, uint32_t & numArchivesOut, uint32_t const maxArchivesOut) const
                                                                                                                                            {
		numArchivesOut = 0;
		node* n = getNodeByArchiveId(id);
		if (!n)
			return false;
		node* parent = n->parent;
		if (!parent)
			return false;

		// Parent must be a routing node.
		if (parent->aid.value != 0)
			return false;
			
		// Root and PLANET-R are never merged.
		if (parent->type == PUVADictConstants::NODE_TYPE_ROOT || parent->type == PUVADictConstants::NODE_TYPE_PLANET_REMAINDER)
			return false;

		for (const node* child : parent->children) {
			if (!child->aid.value)
				return false; // malformed routing node
			STTSAV_ASSERT(numArchivesOut < maxArchivesOut);
			archivesOut[numArchivesOut++] = child->aid;
			}
		return numArchivesOut != 0;
		}
}
namespace sttSav
{
  bool PlanetaryFaceUVArchiveDictionary::mergeArchives (archiveId const * archives, uint32_t const numArchives)
                                                                                  {
		if (!numArchives)
			return false;

		node* first = getNodeByArchiveId(archives[0]);
		if (!first)
			return false;
		node* parent = first->parent;
		if (!parent)
			return false;

		// Parent must currently be routing.
		STTSAV_ASSERT(parent->aid.value == 0);

		// Verify every archive belongs to this parent.
		for (uint32_t i = 0; i < numArchives; ++i) {
			node* n = getNodeByArchiveId(archives[i]);
			if (!n)
				return false;
			if (n->parent != parent)
				return false;
			}

		// Delete every child.
		while (!parent->children.empty()) {
			node* child = parent->children.back();
			parent->children.pop_back();
			clearLookup(child->aid);
			STTSAV_DEL(child, sizeof(node));
			}
		// Parent becomes an archive again.
		parent->aid = getNextId();
		insertLookup(parent);
		return true;
		}
}
